/// The value broadcast from a singleflight leader to all followers.
///
/// `Arc<LiterLlmError>` is used because `LiterLlmError` is not `Clone` and
/// broadcast channels require `T: Clone`.  The `Arc` adds only a reference-count
/// bump per follower, which is negligible under the burst loads this layer targets.
pub const SingleflightResult = struct {
    _handle: *anyopaque,

    /// Release the underlying FFI handle. Safe to call once per instance.
    pub fn free(self: *SingleflightResult) void {
        c.literllm_singleflight_result_free(@as(*c.LITERLLMSingleflightResult, @ptrCast(self._handle)));
    }
};

